{
  "domain_analysis": {
    "business_context": "A logistics platform managing parcel delivery through a shipment lifecycle. Shipments progress through defined states with irreversible transitions, are constrained by physical weight limits, and are classified into pricing tiers based on weight brackets.",
    "bounded_context": "Shipment Management — covers shipment creation, state lifecycle, weight validation, and weight-based pricing classification.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A domain entity representing a parcel moving from a pickup address to a delivery address, with a defined weight and lifecycle state." },
      { "term": "Pickup Address", "definition": "The origin location where a parcel is collected from the sender." },
      { "term": "Delivery Address", "definition": "The destination location where a parcel is delivered to the recipient." },
      { "term": "Shipment State", "definition": "The current lifecycle phase of a shipment. Valid states: Pending, In Transit, Delivered." },
      { "term": "Weight Bracket", "definition": "A pricing classification tier determined by the shipment's weight: Standard (0–10 kg), Heavy (10–50 kg), Freight (over 50 kg)." },
      { "term": "Standard", "definition": "Weight bracket for shipments weighing more than 0 kg up to and including 10 kg." },
      { "term": "Heavy", "definition": "Weight bracket for shipments weighing more than 10 kg up to and including 50 kg." },
      { "term": "Freight", "definition": "Weight bracket for shipments weighing more than 50 kg up to and including 1000 kg." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A shipment requires both a pickup address and a delivery address to be created.",
      "invariant": true,
      "invariant_justification": "A shipment without both endpoints is physically meaningless — there is no origin to collect from or destination to deliver to. This is a data integrity constraint.",
      "testable_assertion": "Any attempt to create a shipment with a missing pickup address or missing delivery address must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Shipment state transitions are forward-only: Pending → In Transit → Delivered. A shipment In Transit cannot revert to Pending.",
      "invariant": true,
      "invariant_justification": "Backward state transitions would corrupt the shipment lifecycle and contradict the physical reality of logistics operations. Once a parcel is picked up and moving, it cannot be 'un-picked-up.'",
      "testable_assertion": "Transitioning a shipment from In Transit to Pending must be rejected by the system."
    },
    {
      "id": "BR-3",
      "rule": "Delivered is a terminal state — no further state changes are permitted on a delivered shipment.",
      "invariant": true,
      "invariant_justification": "Delivery is a finalized business event (proof of delivery, billing triggered, custody transferred). Allowing state changes after delivery would corrupt audit trails and financial records.",
      "testable_assertion": "Any attempt to change the state of a Delivered shipment (to Pending, In Transit, or any other state) must be rejected."
    },
    {
      "id": "BR-4",
      "rule": "Shipment weight must be strictly greater than 0 kg and must not exceed 1000 kg.",
      "invariant": true,
      "invariant_justification": "A zero or negative weight is physically impossible for a real parcel. The 1000 kg upper bound is a physical/operational constraint of the platform's handling capacity — accepting heavier shipments would violate safety and equipment limits.",
      "testable_assertion": "Creating or updating a shipment with weight <= 0 or weight > 1000 must be rejected."
    },
    {
      "id": "BR-5",
      "rule": "Weight bracket classification: Standard is 0 < weight ≤ 10 kg, Heavy is 10 < weight ≤ 50 kg, Freight is 50 < weight ≤ 1000 kg.",
      "invariant": false,
      "invariant_justification": "Weight bracket thresholds and their names are business pricing policy — a VP could adjust the boundaries (e.g., move Heavy to 15 kg) or add new tiers without corrupting system state.",
      "testable_assertion": "A 10 kg shipment must be classified as Standard; a 10.01 kg shipment must be classified as Heavy; a 50 kg shipment must be classified as Heavy; a 50.01 kg shipment must be classified as Freight."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A request to create a shipment with a valid pickup address and a valid delivery address",
      "when": "The shipment is created",
      "then": "The shipment is persisted in Pending state with both addresses recorded"
    },
    {
      "id": "AC-2",
      "given": "A request to create a shipment where the pickup address is missing",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating pickup address is required"
    },
    {
      "id": "AC-3",
      "given": "A request to create a shipment where the delivery address is missing",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating delivery address is required"
    },
    {
      "id": "AC-4",
      "given": "A shipment in Pending state",
      "when": "The shipment is transitioned to In Transit",
      "then": "The state changes to In Transit successfully"
    },
    {
      "id": "AC-5",
      "given": "A shipment in In Transit state",
      "when": "An attempt is made to transition it back to Pending",
      "then": "The system rejects the transition and the shipment remains In Transit"
    },
    {
      "id": "AC-6",
      "given": "A shipment in In Transit state",
      "when": "The shipment is transitioned to Delivered",
      "then": "The state changes to Delivered successfully"
    },
    {
      "id": "AC-7",
      "given": "A shipment in Delivered state",
      "when": "Any state change is attempted",
      "then": "The system rejects the transition and the shipment remains Delivered"
    },
    {
      "id": "AC-8",
      "given": "A shipment being created with weight of 0 kg, -5 kg, or 1001 kg",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating weight must be between 0 (exclusive) and 1000 (inclusive)"
    },
    {
      "id": "AC-9",
      "given": "A shipment with weight of exactly 10 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as Standard"
    },
    {
      "id": "AC-10",
      "given": "A shipment with weight of 10.01 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as Heavy"
    },
    {
      "id": "AC-11",
      "given": "A shipment with weight of exactly 50 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as Heavy"
    },
    {
      "id": "AC-12",
      "given": "A shipment with weight of 50.01 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as Freight"
    },
    {
      "id": "AC-13",
      "given": "A shipment with weight of exactly 1000 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as Freight and accepted (boundary of maximum weight)"
    }
  ],

  "edge_cases": [
    { "scenario": "Shipment created with weight of exactly 10 kg", "expected_behavior": "Classified as Standard (upper-bound inclusive for Standard tier)." },
    { "scenario": "Shipment created with weight of exactly 50 kg", "expected_behavior": "Classified as Heavy (upper-bound inclusive for Heavy tier)." },
    { "scenario": "Shipment created with weight of exactly 1000 kg", "expected_behavior": "Accepted and classified as Freight (maximum allowed weight)." },
    { "scenario": "Shipment created with weight of 0.001 kg", "expected_behavior": "Accepted and classified as Standard (smallest valid weight)." },
    { "scenario": "Attempt to transition a Pending shipment directly to Delivered", "expected_behavior": "Spec is ambiguous — must the shipment pass through In Transit first, or is Pending → Delivered allowed? See escalation." },
    { "scenario": "Attempt to create a shipment without specifying weight", "expected_behavior": "Rejected — weight is a required attribute since pricing depends on it." },
    { "scenario": "Delivered shipment where someone attempts to update the weight or addresses", "expected_behavior": "Spec says state cannot change; should be clarified whether non-state attributes are also immutable after delivery." },
    { "scenario": "Pickup and delivery addresses are identical", "expected_behavior": "Not addressed in spec — may be a valid scenario (e.g., return to same location) or a user error. Needs clarification." }
  ],

  "business_impact": {
    "financial": "Weight bracket classification directly drives pricing and revenue. Incorrect bracket assignment means under- or over-charging. The 1000 kg cap defines the platform's serviceable market — shipments above this are out of scope and require partner freight carriers.",
    "operational": "State lifecycle integrity is critical for dispatch, tracking, and proof-of-delivery workflows. Allowing backward transitions would break driver assignment, route planning, and warehouse operations. Weight validation prevents accepting shipments the fleet cannot physically handle.",
    "user": "Senders need clear feedback when shipments are rejected (missing address, invalid weight). Recipients rely on accurate state tracking. Both parties trust that Delivered means delivered — any state regression erodes trust.",
    "risk": "Primary risk is boundary ambiguity at weight bracket edges (10 kg, 50 kg) leading to pricing disputes. Secondary risk is the unspecified Pending → Delivered transition — if allowed, it could bypass In Transit tracking and auditing. Terminal state immutability must extend to all attributes, not just state, to prevent post-delivery fraud.",
    "stakeholders_affected": [
      { "group": "Senders / Shippers", "impact": "Must provide valid addresses and weight; receive pricing based on weight bracket. Rejected at creation if data is invalid." },
      { "group": "Recipients", "impact": "Rely on accurate shipment state for delivery expectations. Delivered status must be trustworthy and final." },
      { "group": "Operations / Dispatch", "impact": "Depend on forward-only state machine to plan routes, assign drivers, and manage warehouse flow." },
      { "group": "Finance / Billing", "impact": "Weight bracket determines charge amount. Delivered finality triggers invoicing — state regression would create billing inconsistencies." },
      { "group": "Customer Support", "impact": "Need clarity on whether Pending → Delivered is valid, and whether attributes can change post-delivery, to handle disputes." }
    ]
  },

  "confidence": {
    "level": 55,
    "reasoning": "The spec clearly defines weight constraints, bracket pricing, and the In Transit → Pending prohibition. However, it leaves ambiguity on key boundary behaviors: whether Pending → Delivered is a valid skip-transition, whether bracket boundaries are inclusive at the upper or lower end, and whether Delivered immutability extends beyond state to all shipment attributes. These gaps could lead to implementation disagreements.",
    "high_confidence_areas": [
      "Weight must be positive and ≤ 1000 kg (explicitly stated)",
      "In Transit cannot revert to Pending (explicitly stated)",
      "Delivered is terminal — no state changes (explicitly stated)",
      "Shipment requires both pickup and delivery addresses (explicitly stated)",
      "Three weight brackets exist: Standard, Heavy, Freight"
    ],
    "low_confidence_areas": [
      "Whether Pending → Delivered is a valid transition (skipping In Transit)",
      "Whether weight bracket boundaries are inclusive at upper or lower bound (is exactly 10 kg Standard or Heavy?)",
      "Whether Delivered immutability extends to non-state attributes (weight, addresses)",
      "Whether pickup and delivery addresses can be identical",
      "Whether weight can be changed on an existing shipment in Pending or In Transit states"
    ],
    "assumptions": [
      "The only valid states are Pending, In Transit, and Delivered — no Cancelled or Failed state exists",
      "Weight bracket boundaries are upper-bound inclusive based on the phrasing '0-10 kg is standard' meaning ≤ 10",
      "Weight is required at shipment creation since pricing depends on it",
      "A newly created shipment starts in Pending state"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec prohibits In Transit → Pending but does not address whether Pending → Delivered is a valid transition. In logistics, this could represent a direct hand-delivery or local pickup scenario, but it could also be an unintended bypass of tracking.",
      "affected_stakeholders": ["Operations / Dispatch", "Finance / Billing", "Customer Support"],
      "options": [
        "A: Allow Pending → Delivered (supports edge cases like local pickup)",
        "B: Require Pending → In Transit → Delivered (enforces full tracking pipeline)"
      ],
      "recommendation": "Option B — require full lifecycle. Local pickup and hand-delivery should still pass through In Transit to maintain audit trail and trigger dispatch events. A skip would leave gaps in tracking and billing."
    },
    {
      "type": "ambiguity",
      "description": "Weight bracket boundary inclusion is not explicit. The phrasing '0-10 kg is standard, 10-50 kg is heavy' places 10 kg in both ranges and 50 kg in both Heavy and Freight ranges. The boundary ownership must be specified.",
      "affected_stakeholders": ["Finance / Billing", "Senders / Shippers"],
      "options": [
        "A: Upper-bound inclusive (Standard: 0 < w ≤ 10, Heavy: 10 < w ≤ 50, Freight: 50 < w ≤ 1000)",
        "B: Lower-bound inclusive (Standard: 0 < w < 10, Heavy: 10 ≤ w < 50, Freight: 50 ≤ w ≤ 1000)"
      ],
      "recommendation": "Option A — upper-bound inclusive. This favors the customer (10 kg stays in the cheaper Standard tier) and is the more common convention in logistics pricing. But this must be confirmed by Product to avoid billing disputes."
    },
    {
      "type": "ambiguity",
      "description": "The spec says 'Delivered shipments are final — their state cannot change' but does not clarify whether non-state attributes (weight, addresses) are also immutable after delivery. Allowing address or weight edits post-delivery could enable fraud or break billing records.",
      "affected_stakeholders": ["Finance / Billing", "Customer Support", "Senders / Shippers"],
      "options": [
        "A: Only state is immutable after delivery — other attributes remain editable",
        "B: The entire shipment record becomes immutable after delivery"
      ],
      "recommendation": "Option B — full immutability. Delivered shipments represent completed business transactions. Weight changes would alter the invoice; address changes would corrupt the delivery record. Corrections should go through a separate dispute/amendment process."
    }
  ],

  "rejection_reasons": []
}

